
import ReactDOM from 'react-dom/client';
import App from './App'
import ALLAbout from './About/ALLAbout';
import AllAffairs from './Affairs/AllAffairs';
import AllSubject from './Subject/AllSubject';
import {createBrowserRouter, RouterProvider,} from "react-router";



 var figam = createBrowserRouter([
    {
      path : "/",
      element:<App/>
    },
    {
        path :"About",
        element :<ALLAbout/>
    },
    {
      path :"Affairs",
      element:<AllAffairs/>
    },
    {
      path:"Subject",
      element:<AllSubject/>
    },
    


]);


const root = ReactDOM.createRoot(document.getElementById('root'));

root.render(<RouterProvider router={figam}/>);

